const PB_URL=($('Config').first().json.pbUrl||'').replace(/\/+$/,'');
const token=$('PB Auth').first().json.token; const pbH={Authorization:token};
const body=($('Webhook').first().json.body)||{};
const fedId=body.id; const url=body.url; const country=body.country||''; const prefix=body.prefix||'X'; const mode=body.mode||'cyp_li'; const region=body.region||'';
if(!fedId||!url) return [{json:{error:'need id+url'}}];
const uslug=(s)=>String(s||'').toLowerCase().trim().replace(/[^\p{L}\p{N}]+/gu,'-').replace(/^-+|-+$/g,'');
const strip=(s)=>s.replace(/<[^>]+>/g,'').replace(/&amp;/g,'&').replace(/&nbsp;/g,' ').replace(/&#?[a-z0-9]+;/gi,' ').replace(/\s+/g,' ').trim();
const now=new Date().toISOString();
const findClub=async(k)=>{const r=await this.helpers.httpRequest({method:'GET',url:PB_URL+'/api/collections/clubs/records',qs:{filter:"(dedup_key='"+k+"')",perPage:1},headers:pbH,json:true});return (r.items&&r.items[0])||null;};
let html='';
const BH={'User-Agent':'Mozilla/5.0 (X11; Linux x86_64) AppleWebKit/537.36 (KHTML, like Gecko) Chrome/120.0 Safari/537.36','Accept':'text/html,application/xhtml+xml,application/xml;q=0.9,*/*;q=0.8','Accept-Language':'en-US,en;q=0.9'};
try{html=String(await this.helpers.httpRequest({method:'GET',url,headers:BH}));}catch(e){return [{json:{error:'fetch:'+e.message}}];}
let names=[];
if(mode==='cyp_li'){
  const lis=html.match(/<li[^>]*>[\s\S]*?<\/li>/g)||[];
  for(const x of lis){const t=strip(x); if(/[\u0370-\u03ff\u1f00-\u1fff]/.test(t) && t.length>3 && t.length<60 && !/http|menu/i.test(t)) names.push(t);}
}else if(mode==='lat_td'){
  const rows=html.match(/<tr[^>]*>[\s\S]*?<\/tr>/g)||[];
  for(const r of rows){const tds=r.match(/<td[^>]*>[\s\S]*?<\/td>/g)||[]; if(tds.length<2)continue; const t=strip(tds[1]); if(t && t.toLowerCase()!=='komanda' && !/^nr\.?$/i.test(t) && t.length>2) names.push(t);}
}
const seen={}; const uniq=[]; for(const n of names){const k=uslug(n); if(k&&!seen[k]){seen[k]=1;uniq.push(n);}}
let created=0,updated=0;
for(const name of uniq){const dedup=prefix+':'+uslug(name);
  const base={federation:fedId,name,country,region,dedup_key:dedup,source_url:url,website_source:'none',status:'new',last_scraped:now};
  try{ try{await this.helpers.httpRequest({method:'POST',url:PB_URL+'/api/collections/clubs/records',headers:pbH,body:base,json:true});created++;}
    catch(e){const ex=await findClub(dedup);if(ex){await this.helpers.httpRequest({method:'PATCH',url:PB_URL+'/api/collections/clubs/records/'+ex.id,headers:pbH,body:{name,country,region,source_url:url,last_scraped:now},json:true});updated++;}else throw e;} }
  catch(e){continue;}
}
let n=0; try{const r=await this.helpers.httpRequest({method:'GET',url:PB_URL+'/api/collections/clubs/records',qs:{filter:'federation="'+fedId+'"',perPage:1},headers:pbH,json:true});n=r.totalItems||0;}catch(e){}
await this.helpers.httpRequest({method:'PATCH',url:PB_URL+'/api/collections/federations/records/'+fedId,headers:pbH,body:{status:(n>0?'scraped':'needs_review'),club_count:n,last_scraped:now},json:true});
return [{json:{mode,found:uniq.length,created,updated,fedClubs:n}}];
